"use client"

import React from "react"
import { XIcon } from "lucide-react"
import {
  MorphingDialog,
  MorphingDialogTrigger,
  MorphingDialogContainer,
  MorphingDialogContent,
  MorphingDialogClose,
} from "@/components/ui/morphing-dialog"

type Project = {
  name: string
  description: string
  link: string
  video: string
  id: string
}

const PROJECTS: Project[] = [
