                      <span className="text-sm font-medium text-muted-foreground">Speed</span>
                      {[0.5, 1, 1.5, 2].map((s) => (
                        <Button
                          key={s}
                          variant={playbackSpeed === s ? "default" : "outline"}
                          size="sm"
                          className="w-full"
                          onClick={() => {
                            if (videoRef.current) videoRef.current.playbackRate = s;
                            setPlaybackSpeed(s);
                          }}
