                </Popover>

                {/* Fullscreen */}
                <Button variant="ghost" size="icon" className="text-white" onClick={toggleFullscreen}>
                  <Maximize2 className="w-5 h-5" />
                </Button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default VideoPlayerPro;


